#include <stdio.h>
#include <stdlib.h>
#include <limits.h>

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n; scanf("%d", &n);
        int **a = (int**)malloc(n * sizeof(int*));
        for (int i = 0; i < n; ++i) {
            a[i] = (int*)malloc(n * sizeof(int));
            for (int j = 0; j < n; ++j) {
                scanf("%d", &a[i][j]);
            }
        }
        for (int i = 1; i < n; ++i) {
            for (int j = 0; j < n; ++j) {
                int best = a[i-1][j];
                if (j > 0 && a[i-1][j-1] < best) best = a[i-1][j-1];
                if (j + 1 < n && a[i-1][j+1] < best) best = a[i-1][j+1];
                a[i][j] += best;
            }
        }
        int ans = INT_MAX;
        for (int j = 0; j < n; ++j) if (a[n-1][j] < ans) ans = a[n-1][j];
        printf("%d\n", ans);
        for (int i = 0; i < n; ++i) free(a[i]);
        free(a);
    }
    return 0;
}

