import sys

def solve():
    data = list(map(int, sys.stdin.read().strip().split()))
    if not data:
        return
    it = iter(data)
    T = next(it)
    out = []
    for _ in range(T):
        n = next(it)
        a = [[next(it) for _ in range(n)] for __ in range(n)]
        for i in range(1, n):
            for j in range(n):
                best = a[i-1][j]
                if j > 0:
                    best = min(best, a[i-1][j-1])
                if j + 1 < n:
                    best = min(best, a[i-1][j+1])
                a[i][j] += best
        out.append(str(min(a[-1])))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

